import React from 'react';
import DateTimePicker, {type DatePickerOptions} from '@react-native-community/datetimepicker';
import type {IFlexComponent, IKitsInputCalendar} from '@lmb/kitsconcerto-types';
import KitsContainer from '../../Helpers/FormContainer';
import {useFormInputController} from '../../Helpers/useFormInputController';
import Addons from '../../Helpers/Addons';
import {Flex, Text} from "../../../../";
import {useComponentDefaults} from '@lmb/kitsconcerto/Hooks';
import {useKitsTheme} from '@lmb/kitsconcerto';

const KitsInputCalendar = <T = DatePickerOptions,>({ ref, ...rawProps }: IKitsInputCalendar<T>) => {
    const { mergedProps: props, themeStyle } = useComponentDefaults('Datepicker', rawProps as any, 'Input');
    const {resolveToken} = useKitsTheme();
    const {
        id, label, helperText, errors, invalid,
        required, hideError, disabled, isFloatedLabel,
        leftAddon, rightAddon, inputSize,
        value, defaultValue, onChange,
        localProps = {},
    } = props;

    const { value: internalVal, emitChange } = useFormInputController<Date | null>({
        value: value as (Date | null),
        defaultValue: defaultValue as (Date | null),
        onChange: (event) => {
            onChange?.(event.target.value)
        },
    });

    const onSelectDate = (_event: any, date?: Date) => {
        if (date) emitChange(date);
    };

    const containerStyle: IFlexComponent = {
        height: 35,
        flexDirection: "row",
        alignContent: "center",
        alignItems: "center",
        overflow: "hidden",
        borderRadius: 3.5,
        borderWidth: 1,
        borderColor: invalid ? resolveToken('danger') : resolveToken('border'),
        width: "100%",
        ...(themeStyle as any),
    }

    const val = internalVal instanceof Date ? internalVal : new Date()
    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={label}
            required={required}
            hideError={hideError}
            isFloatedLabel={isFloatedLabel}
            disabled={disabled}
        >
            <Flex {...containerStyle}>
                <Addons leftAddon={leftAddon} rightAddon={rightAddon} invalid={!!invalid}>
                    <Flex alignItems={'center'} w={'full'} backgroundColor={resolveToken('text-secondary')}>
                        <DateTimePicker
                            value={val}
                            onChange={onSelectDate}
                            mode="date"
                            display="default"
                            disabled={disabled}
                            {...localProps}
                        />

                        <Flex alignItems={'center'} w={'full'} h={'full'} paddingHorizontal={10} backgroundColor={resolveToken('surface-card')} pointerEvents={'none'} position={'absolute'} top={0}>

                            <Text>{val.toLocaleDateString()}</Text>
                        </Flex>
                    </Flex>

                </Addons>
            </Flex>
        </KitsContainer>
    );
};

export default KitsInputCalendar;
